/* ---------------- Typing Animation ---------------- */
.hero-type {
  font-family: monospace;
  font-size: 28px;
  white-space: nowrap;
  overflow: hidden;
  border-right: 3px solid black;
  width: fit-content;
  margin: 0 auto 60px;
  animation: typing 2.5s steps(20, end), blink 0.7s step-end infinite;
}

@keyframes typing {
  from { width: 0 }
  to { width: 20ch }
}

@keyframes blink {
  50% { border-color: transparent }
}

/* ---------------- Project Cards ---------------- */
.card-grid {
  display: flex;
  gap: 30px;
  justify-content: center;
  margin-bottom: 60px;
}

.card {
  position: relative;
  width: 220px;
  height: 140px;
  background: #007bff;
  border-radius: 10px;
  overflow: hidden;
  cursor: pointer;
}

/* Hover Overlay */
.overlay {
  position: absolute;
  bottom: -100%;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.7);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: bottom 0.4s ease;
  font-weight: bold;
}

.card:hover .overlay {
  bottom: 0;
}

