}
.flip-inner {
  width: 100%;
  height: 100%;
  transition: transform 0.6s;
  transform-style: preserve-3d;
  position: relative;
}
.flip-card:hover .flip-inner {
  transform: rotateY(180deg);
}
.flip-front, .flip-back {
  position: absolute;
  width: 100%;
  height: 100%;
  backface-visibility: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  border: 1px solid #ccc;
}
.flip-front {
  background: #f0f0f0;
}
.flip-back {
  background: #6200ea;
  color: white;
  transform: rotateY(180deg);
}

/* 2. Letter-by-Letter Reveal */
.reveal-text {
  font-size: 28px;
  font-weight: bold;
  display: flex;
  gap: 5px;
}
.reveal-text span {
  opacity: 0;
  transform: translateY(20px);
  animation: reveal 0.5s forwards;
  animation-delay: calc(var(--i) * 0.2s);
}
@keyframes reveal {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* 3. Typing Effect */
.typing-box {
  width: fit-content;
  border-right: 2px solid black;
  white-space: nowrap;
  overflow: hidden;
}
.typing-text {
  font-family: monospace;
  font-size: 20px;
  animation: typing 4s steps(30) forwards, blink 0.7s step-end infinite;
}
@keyframes typing {
  from { width: 0 }
  to { width: 100% }
}
@keyframes blink {
  50% { border-color: transparent; }
}

/* 4. Overlay on Hover */
.overlay-card {
  width: 200px;
  height: 120px;
  background: #ccc;
  position: relative;
  overflow: hidden;
}
.overlay-content {
  position: absolute;
  bottom: 0;
  background: rgba(0,0,0,0.7);
  color: white;
  width: 100%;
  text-align: center;
  padding: 10px;
  transform: translateY(100%);
  transition: 0.3s;
}
.overlay-card:hover .overlay-content {
  transform: translateY(0);
}

