.grid-container {
  display: flex;
  gap: 20px;
}
.grid-card {
  width: 100px;
  height: 100px;
  background: #2196f3;
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transform: translateY(30px);
  animation: fadeUp 0.5s forwards;
}
.grid-card:nth-child(1) { animation-delay: 0.1s; }
.grid-card:nth-child(2) { animation-delay: 0.3s; }
.grid-card:nth-child(3) { animation-delay: 0.5s; }
@keyframes fadeUp {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* 6. CSS Modal */
.open-modal-button {
  display: inline-block;
  padding: 10px 20px;
  background: #6200ea;
  color: white;
  border-radius: 5px;
  cursor: pointer;
  font-weight: bold;
}
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.6);
  opacity: 0;
  pointer-events: none;
  transition: 0.3s;
  z-index: 9;
}
.modal-box {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.8);
  background: white;
  padding: 30px;
  width: 300px;
  border-radius: 10px;
  box-shadow: 0 0 25px rgba(0, 0, 0, 0.3);
  opacity: 0;
  pointer-events: none;
  transition: 0.3s ease-in-out;
  z-index: 10;
  text-align: center;
}
.modal-close {
  position: absolute;
  top: 10px;
  right: 15px;
  font-size: 20px;
  cursor: pointer;
  color: #888;
  font-weight: bold;
}
#modal-toggle:checked ~ .modal-overlay {
  opacity: 1;
  pointer-events: all;
}
#modal-toggle:checked ~ .modal-box {
  transform: translate(-50%, -50%) scale(1);
  opacity: 1;
  pointer-events: all;
}

