.progress-bar {
  width: 400px;
  height: 20px;
  background: #ddd;
  border-radius: 10px;
  overflow: hidden;
  margin-top: 60px;
}

.progress-fill {
  height: 100%;
  width: 0%;
  background: #28a745;
  animation: loadProgress 5s ease forwards;
}

/* Multi-step animation */
@keyframes loadProgress {
  0%   { width: 0%;   background: #ffc107; }
  30%  { width: 30%;  background: #17a2b8; }
  60%  { width: 60%;  background: #007bff; }
  80%  { width: 80%;  background: #6610f2; }
  100% { width: 100%; background: #28a745; }
}

/* Hidden checkbox */
#modal-toggle {
  display: none;
}

/* Trigger button */
.open-btn {
  background: #007bff;
  padding: 12px 24px;
  color: white;
  border-radius: 4px;
  cursor: pointer;
}

/* Modal backdrop */
.modal {
  position: fixed;
  top: 0; left: 0;
  width: 100vw; height: 100vh;
  background: rgba(0,0,0,0.6);
  display: flex;
  justify-content: center;
  align-items: center;
  opacity: 0;
  pointer-events: none;
  transition: 0.3s ease;
}

/* Modal box */
.modal-content {
  background: white;
  padding: 30px;
  border-radius: 8px;
  width: 320px;
  text-align: center;
  position: relative;
}

/* Close button */
.close-btn {
  position: absolute;
  top: 10px;
  right: 12px;
  font-size: 20px;
  cursor: pointer;
  color: red;
}

/* When checkbox is checked, show modal */
#modal-toggle:checked ~ .modal {
  opacity: 1;
  pointer-events: auto;
}

